module fsm
(
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);
// TODO: Implement your Mealy FSM design here, using the input and output
// ports provided. Remember, you are being asked to detect a single-bit
// input sequence. Support for continuous input and loop detection.
// Your code starts here
reg [3:0] state, next_state;
parameter S0 = 4'b0000; // Initial state
parameter S1 = 4'b0001; // State when input is 1
parameter S2 = 4'b0010; // State when input is 0
parameter S3 = 4'b0011; // State when input is 1
parameter S4 = 4'b0100; // State when input is 1
parameter S5 = 4'b0101; // State when input is 0
parameter S6 = 4'b0110; // State when input is 0
parameter S7 = 4'b0111; // State when input is 1
parameter S8 = 4'b1000; // State when input is 1
reg [3:0] count;
always @(IN or state or match_reg) begin
    case (state)
        S0: begin
            if (IN == 1'b1)
                next_state = S1;
            else
                next_state = S0;
        end
        S1: begin
            if (IN == 1'b0)
                next_state = S2;
            else
                next_state = S1;
        end
        S2: begin
            if (IN == 1'b0)
                next_state = S3;
            else
                next_state = S1;
        end
        S3: begin
            if (IN == 1'b1)
                next_state = S4;
            else
                next_state = S0;
        end
        S4: begin
            if (IN == 1'b1)
                next_state = S5;
            else
                next_state = S0;
        end
        S5: begin
            if (IN == 1'b0)
                next_state = S6;
            else
                next_state = S1;
        end
        S6: begin
            if (IN == 1'b0)
                next_state = S7;
            else
                next_state = S1;
        end
        S7: begin
            if (IN == 1'b1)
                next_state = S8;
            else
                next_state = S0;
        end
        S8: begin
            if (match_reg == 1'b1)
                next_state = S8;
            else
                next_state = S0;
        end
        default: next_state = S0;
    endcase
end
always @(posedge CLK or negedge RST) begin
    if (!RST) begin
        state <= S0;
        MATCH <= 1'b0;
    end else begin
        state <= next_state;
        MATCH <= (state == S8) ? 1'b1 : 1'b0;
    end
end
// Your code ends here
endmodule
